# Category: serverless_security

import boto3
import json

def lambda_handler(event, context):
    s3 = boto3.client('s3')
    sns = boto3.client('sns')

    # Extract bucket name and object key from the event
    bucket_name = event['Records'][0]['s3']['bucket']['name']
    object_key = event['Records'][0]['s3']['object']['key']

    try:
        # Read image from S3
        response = s3.get_object(Bucket=bucket_name, Key=object_key)
        image_data = response['Body'].read()

        # Process the image (this is a placeholder for your actual processing logic)
        processed_image_data = image_data  # Replace this with actual processing

        # Write processed image back to S3
        output_object_key = f"processed/{object_key}"
        s3.put_object(Bucket=bucket_name, Key=output_object_key, Body=processed_image_data)

        # Send notification via SNS
        message = {
            'bucket': bucket_name,
            'input_key': object_key,
            'output_key': output_object_key
        }
        sns.publish(
            TopicArn='your_sns_topic_arn',
            Message=json.dumps(message),
            Subject='Image Processing Completed'
        )

        # Log to CloudWatch (this is a placeholder for your actual logging logic)
        print(f"Processed image: {output_object_key}")

    except Exception as e:
        print(f"Error processing image: {str(e)}")

